In a well-structured application architecture, the services layer should not talk directly to the database session. Instead, it should interact with a repository layer that abstracts the database operations. This approach provides several benefits:

1. **Separation of Concerns**: The repository layer handles database-specific operations, while the services layer focuses on business logic.
2. **Testability**: By decoupling the services layer from the database, you can easily mock the repository layer during unit testing.
3. **Flexibility**: If you need to change the database or ORM technology, you only need to modify the repository layer, not the entire application.

Here's a typical architecture with a repository layer:

### Repository Layer

The repository layer is responsible for interacting with the database and providing a clean interface for the services layer to use. It encapsulates all database operations and provides methods for CRUD operations.

```python
from sqlalchemy.orm import Session
from .models import User
from .schemas import UserCreate, UserUpdate

class UserRepository:
    def __init__(self, db: Session):
        self.db = db

    def get_user(self, user_id: int) -> User:
        return self.db.query(User).filter(User.id == user_id).first()

    def get_users(self, skip: int = 0, limit: int = 100) -> list[User]:
        return self.db.query(User).offset(skip).limit(limit).all()

    def create_user(self, user: UserCreate) -> User:
        db_user = User(email=user.email, hashed_password=get_password_hash(user.password))
        self.db.add(db_user)
        self.db.commit()
        self.db.refresh(db_user)
        return db_user

    def update_user(self, user_id: int, user: UserUpdate) -> User:
        db_user = self.get_user(user_id)
        if db_user:
            db_user.email = user.email
            db_user.hashed_password = get_password_hash(user.password)
            self.db.commit()
            self.db.refresh(db_user)
        return db_user

    def delete_user(self, user_id: int) -> None:
        db_user = self.get_user(user_id)
        if db_user:
            self.db.delete(db_user)
            self.db.commit()
```

### Services Layer

The services layer contains the business logic and interacts with the repository layer to perform operations.

```python
from sqlalchemy.orm import Session
from .repositories import UserRepository
from .schemas import UserCreate, UserUpdate

class UserService:
    def __init__(self, db: Session):
        self.user_repo = UserRepository(db)

    def get_user(self, user_id: int) -> User:
        return self.user_repo.get_user(user_id)

    def get_users(self, skip: int = 0, limit: int = 100) -> list[User]:
        return self.user_repo.get_users(skip, limit)

    def create_user(self, user: UserCreate) -> User:
        return self.user_repo.create_user(user)

    def update_user(self, user_id: int, user: UserUpdate) -> User:
        return self.user_repo.update_user(user_id, user)

    def delete_user(self, user_id: int) -> None:
        self.user_repo.delete_user(user_id)
```

### FastAPI Integration

